import { streamText } from 'ai';
import { z } from 'zod';

const detectHallucinations = async (chunks: string[]) => {
  const hallucinationPatterns = [
    /\b(19|20)\d{2}\b(?=\s*(?!-))/, // Fake years
    /\b[A-Z][a-z]+\s[A-Z][a-z]+\s+(PhD|MD|CEO)\b/, // Fake credentials
  ];
  return chunks.some(chunk => 
    hallucinationPatterns.some(pattern => pattern.test(chunk))
  );
};

export async function streamAgent(userMessage: string) {
  const result = await streamText({
    model: openai('gpt-4o'),
    messages: [{ role: 'user', content: userMessage }],
  });

  let chunks: string[] = [];
  for await (const chunk of result.textStream) {
    chunks.push(chunk);
    if (await detectHallucinations(chunks)) {
      console.error('🚨 Hallucination detected in stream');
    }
    // ... yield to UI
  }
}

import { streamText, tool } from 'ai';
import { z } from 'zod';

const mathTool = tool({
  description: 'Calculator',
  parameters: z.object({
    expression: z.string().regex(/^[0-9+\-*/().\s]+$/),
  }),
  execute: async ({ expression }) => eval(expression),
});

export async function agentStream(input: string) {
  const result = await streamText({
    model: openai('gpt-4o'),
    tools: { mathTool },
    messages: [{ role: 'user', content: input }],
  });

  for await (const chunk of result.fullStream) {
    if (chunk.type === 'tool-call') {
      const validated = mathTool.parameters.safeParse(chunk.args);
      if (!validated.success) {
        console.error('🚨 Invalid tool call:', validated.error);
        // Block render
        return;
      }
    }
  }
}

import { streamText } from 'ai';

export async function profileAgentTask(prompt: string) {
  const start = performance.now();
  const timeoutThreshold = 25000; // Vercel edge limit

  const result = await Promise.race([
    streamText({
      model: openai('gpt-4o'),
      messages: [{ role: 'user', content: prompt }],
    }),
    new Promise((_, reject) => 
      setTimeout(() => reject(new Error('Agent timeout')), timeoutThreshold)
    ),
  ]);

  const duration = performance.now() - start;
  if (duration > timeoutThreshold * 0.8) {
    console.warn(`🚨 Agent task ${duration}ms exceeds 80% of edge limit`);
  }
  return result;
}

