import { createStreamableUI } from 'ai/rsc';

export async function safeStreamAgent(prompt: string) {
  const ui = createStreamableUI();

  (async () => {
    const result = await streamText({
      model: openai('gpt-4o'),
      messages: [{ role: 'user', content: prompt }],
    });

    let hasHallucinated = false;
    for await (const chunk of result.textStream) {
      if (hallucinationRegex.test(chunk) && !hasHallucinated) {
        ui.update(<div>🔍 Verifying response...</div>);
        hasHallucinated = true;
        continue;
      }
      ui.update(<div>{chunk}</div>);
    }
    ui.done();
  })();

  return ui.value;
}

import { streamText, tool } from 'ai';
import { z } from 'zod';

const safeMathTool = tool({
  parameters: z.object({
    expression: z.string().regex(/^[0-9+\-*/().\s]+$/),
  }),
  execute: async ({ expression }) => {
    try {
      return { result: eval(expression) };
    } catch {
      throw new Error('Invalid expression');
    }
  },
});

export async function validatedAgentStream(input: string) {
  return streamText({
    model: openai('gpt-4o'),
    tools: { safeMathTool },
    messages: [{ role: 'user', content: input }],
    maxSteps: 5, // Prevent infinite loops
  });
}

