import { generateText, streamText } from 'ai';
import { createMiddleware } from '@vex_dev/sdk';

const vexMiddleware = createMiddleware({
  detectors: ['hallucination', 'tool-validation', 'structured-output', 'timeout'],
  autoFix: true,
});

export async function testedAgentStream(prompt: string) {
  return streamText.use(vexMiddleware)({
    model: openai('gpt-4o'),
    messages: [{ role: 'user', content: prompt }],
  });
}

export async function testedGenerate(prompt: string) {
  return generateText.use(vexMiddleware)({
    model: openai('gpt-4o'),
    prompt,
    temperature: 0.1,
  });
}

